python3 -c "import librosa; import numpy as np; y, sr = librosa.load('/workspace/input.wav', sr=None); freqs, times, mags = librosa.reassigned_spectrogram(y, sr=sr); mags_db = librosa.amplitude_to_db(mags); n_bins, n_frames = freqs.shape; target_tones = [220.0, 440.0, 880.0]; match_count = 0
